  5→  Modal,
  6→  StatusBar,
  7→} from '@semparar/design-system-app';
  8→import { ModalLoadingBox, Text } from '@semparar/design-system-app/fintech';
  9→import type { PropsStatusBar } from '@semparar/design-system-app/src/atomic/atoms/StatusBar/Models';
 10→import type { PropsHeader } from '@semparar/design-system-app/src/atomic/molecules/Header/Models';
 11→import React, { FC } from 'react';
 12→import { ScrollView, StyleSheet } from 'react-native';
 13→
 14→import { eventSelectContent } from '~/constants/functions';
 15→import WrapperKeyboardAvoiding from '../WrapperKeyboardAvoiding';
 16→import { BasicScreenViewProps } from './Models';
 17→import { Container, Overlay } from './styles';
 18→
 19→const viewStyles = StyleSheet.create({
 20→  scrollContent: { flexGrow: 1 },
 21→});
 22→
 23→const BasicScreenView: FC<BasicScreenViewProps> = ({
 24→  children,
 25→  title = '',
 26→  hasLeftIcon = true,
 27→  leftIcon = 'icon-back',
 28→  leftIconOnPress = () => {},
 29→  hasRightIcon = false,
 30→  rightIcon = 'icon-close',
 31→  rightIconOnPress = () => {},
 32→  statusBarBg = 'BRAND_BASE_01',
 33→  statusBarProps = {
 34→    barStyle: 'light-content',
 35→  },
 36→  isLoading = false,
 37→  bgColor = 'BRAND_COMPLEMENT_03',
 38→  hasScroll = false,
 39→  hasHeader = true,
 40→  headerTitle,
 41→  scrollViewProps,
 42→  titleColor,
 43→  leftIconColor,
 44→  rightIconColor,
 45→  rightSecondaryIcon,
 46→  rightSecondaryIconNot,
 47→  testID,
 48→  throttle,
 49→  scrollViewRef,
 50→  showValue,
 51→  setShowValue,
 52→  errorButtonOnPress,
 53→  currentRouteName,
 54→  handleGoToHome,
 55→  hasError,
 56→  handleClose,
 57→}) => {
 58→  return (
 59→    <WrapperKeyboardAvoiding>
 60→      <ModalLoadingBox
 61→        onClose={() => null}
 62→        visible={isLoading}
 63→        numberOfLines={1}
 64→        title="Aguarde..."
 65→      />
 66→      <Container testID={testID} bgColor={bgColor}>
 67→        <StatusBar
 68→          bgColor={statusBarBg as PropsStatusBar['bgColor']}
 69→          {...statusBarProps}
 70→        />
 71→        {hasHeader ? (
 72→          <Header
 73→            title={title}
 74→            iconLeft={leftIcon}
 75→            iconRight={rightIcon}
 76→            hideLeftIcon={!hasLeftIcon}
 77→            isOption={hasRightIcon}
 78→            onBack={leftIconOnPress}
 79→            onPressIconRight={rightIconOnPress}
 80→            titleColor={titleColor as PropsHeader['titleColor']}
 81→            iconColorLeft={leftIconColor as PropsHeader['iconColorLeft']}
 82→            iconColorOnOption={
 83→              rightIconColor as PropsHeader['iconColorOnOption']
 84→            }
 85→            testID="icon-home-button"
 86→          />
 87→        ) : null}
 88→        {headerTitle ? (
 89→          <Box
 90→            width="100%"
 91→            bgColor="BRAND_COMPLEMENT_01"
 92→            pd="innerLarge"
 93→            direction
 94→            justify="space-between"
 95→          >
 96→            <Text type="subtitleXXXXL" color="BRAND_COMPLEMENT_02">
 97→              {headerTitle}
 98→            </Text>
 99→            <Box direction justify="space-between">
100→              {rightSecondaryIcon && (
101→                <Icon
102→                  mr="middle"
103→                  onPress={() => setShowValue?.(!showValue)}
104→                  name={showValue ? rightSecondaryIcon : rightSecondaryIconNot}
105→                  color="BRAND_COMPLEMENT_02"
106→                />
107→              )}
108→              <Icon
109→                name={rightIcon}
110→                color="BRAND_COMPLEMENT_02"
111→                onPress={rightIconOnPress}
112→              />
113→            </Box>
114→          </Box>
115→        ) : null}
116→        {hasScroll ? (
117→          <ScrollView
118→            ref={scrollViewRef}
119→            {...scrollViewProps}
120→            scrollEnabled={hasScroll}
121→            scrollEventThrottle={throttle ?? 0}
122→            contentContainerStyle={viewStyles.scrollContent}
123→          >
124→            {children}
125→          </ScrollView>
126→        ) : (
127→          children
128→        )}
129→
130→        {hasError && (
131→          <Overlay>
132→            <Modal
133→              iconBgColor="DENY_COLOR_03"
134→              visible={hasError}
135→              icon="icon-circle-alert"
136→              onPressFirstButton={() => {
137→                eventSelectContent({
138→                  content_type: 'cta',
139→                  content_id: 'tentar_novamente_erro',
140→                  location_1: 'monetizacao',
141→                  location_2: 'spmais',
142→                  location_3: currentRouteName ?? '',
143→                });
144→                errorButtonOnPress();
145→              }}
146→              onPressSecondButton={handleGoToHome}
147→              textFirstButton="Tentar novamente"
148→              textSecondButton="Voltar para Home"
149→              subTitle="Ops, algo deu errado..."
150→              colorSubtitle="BRAND_COMPLEMENT_01"
151→              iconColor="DENY_COLOR_01"
152→              testID="modalApiError"
153→              description="Por favor, tente novamente."
154→              onClose={handleClose}
155→            />
156→          </Overlay>
157→        )}
158→      </Container>
159→    </WrapperKeyboardAvoiding>
160→  );
161→};
162→
163→export default BasicScreenView;
