30→            icon: 'icon-question' as PropsIconsNameCore,
31→          }))}
32→          renderItem={() => <Skeleton width={width} height={72} mb="xxs" />}
33→          keyExtractor={item => item.title}
34→        />
35→      </Box>
36→    );
37→  }
38→
39→  return (
40→    <Box>
41→      <Text type="paragraphXXXL" mb="xxxs">
42→        Saiba mais
