202→        'react-native-safe-area-context',
203→        'react-native-gesture-handler',
204→        'react-native-icomoon',
205→        'react-native-flip-card',
206→        'react-native-linear-gradient',
207→        'react-native-status-bar-height',
208→        'react-native-svg',
209→        'react-native-svg-charts',
210→        '@semparar/design-system-app',
211→      ],
212→    },
213→  },
214→
215→  addons: [
216→    '@storybook/addon-essentials',
217→    path.resolve(__dirname, 'addons/json-editor/register.tsx'),
218→  ],
219→
220→  viteFinal: async config => {
221→    config.plugins = config.plugins || [];
222→    config.plugins.push(dtsStubPlugin());
223→    config.plugins.push(circularFixPlugin());
224→    config.plugins.push(jsxInJsPlugin());
225→    config.plugins.push(cjsToEsmPlugin());
226→
227→    config.optimizeDeps = config.optimizeDeps || {};
228→    config.optimizeDeps.include = [
