233→      'credit-card-type',
234→      'lodash',
235→      'xdate',
236→      'invariant',
237→      'fbjs',
238→      'hoist-non-react-statics',
239→      'prop-types',
240→      'object-assign',
241→      'shallowequal',
242→      'moment',
243→    ];
244→
245→    config.resolve = config.resolve || {};
246→    config.resolve.alias = {
247→      ...(config.resolve.alias || {}),
248→      '~': path.resolve(__dirname, '../src'),
249→      '~/store': path.resolve(__dirname, 'mocks/store.ts'),
250→      'postcss': path.resolve(__dirname, '../node_modules/postcss/lib/postcss.mjs'),
251→      'react-native-linear-gradient': path.resolve(
252→        __dirname,
253→        'mocks/react-native-linear-gradient.tsx',
254→      ),
255→      'react-native-modalize': path.resolve(
256→        __dirname,
257→        'mocks/react-native-modalize.tsx',
258→      ),
259→      'react-native-skeleton-placeholder': path.resolve(
260→        __dirname,
261→        'mocks/react-native-skeleton-placeholder.tsx',
262→      ),
263→      '@react-native-community/slider': path.resolve(
264→        __dirname,
265→        'mocks/react-native-community-slider.tsx',
266→      ),
267→      'lottie-react-native': path.resolve(
268→        __dirname,
269→        'mocks/lottie-react-native.tsx',
270→      ),
271→      'react-native-video': path.resolve(
272→        __dirname,
273→        'mocks/react-native-video.tsx',
274→      ),
275→      '@react-native/assets-registry/registry': path.resolve(
